create extension if not exists pgcrypto;
create table public.doctors (id uuid primary key default gen_random_uuid(), auth_user_id uuid unique references auth.users(id) on delete cascade, doctor_name text not null, clinic_name text not null, specialization text, slug text unique not null, gmb_review_link text, city text, phone text, logo_url text, plan text default 'free', is_active boolean default true, created_at timestamptz default now());
create table public.doctor_keywords (id uuid primary key default gen_random_uuid(), doctor_id uuid not null references public.doctors(id) on delete cascade, keyword text not null, category text default 'care', created_at timestamptz default now());
create table public.qr_codes (id uuid primary key default gen_random_uuid(), doctor_id uuid unique not null references public.doctors(id) on delete cascade, storage_path text not null, target_url text not null, created_at timestamptz default now());
create table public.scans (id uuid primary key default gen_random_uuid(), doctor_id uuid not null references public.doctors(id) on delete cascade, review_generated boolean default false, review_copied boolean default false, redirected_to_gmb boolean default false, user_agent text, created_at timestamptz default now());
create table public.generated_reviews (id uuid primary key default gen_random_uuid(), doctor_id uuid not null references public.doctors(id) on delete cascade, scan_id uuid references public.scans(id) on delete set null, content text not null, selected boolean default false, created_at timestamptz default now());
create table public.admins (auth_user_id uuid primary key references auth.users(id) on delete cascade, created_at timestamptz default now());
alter table public.doctors enable row level security; alter table public.doctor_keywords enable row level security; alter table public.qr_codes enable row level security; alter table public.scans enable row level security; alter table public.generated_reviews enable row level security; alter table public.admins enable row level security;
create function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from admins where auth_user_id=auth.uid())$$;
create policy "owner or admin doctors select" on doctors for select using (auth_user_id=auth.uid() or is_admin());
create policy "owner inserts own doctor" on doctors for insert with check (auth_user_id=auth.uid()); create policy "owner updates own doctor" on doctors for update using (auth_user_id=auth.uid() or is_admin()) with check (auth_user_id=auth.uid() or is_admin());
create policy "tenant keywords read" on doctor_keywords for select using (exists(select 1 from doctors d where d.id=doctor_id and (d.auth_user_id=auth.uid() or d.is_active=true)) or is_admin());
create policy "tenant keywords write" on doctor_keywords for all using (exists(select 1 from doctors d where d.id=doctor_id and d.auth_user_id=auth.uid()) or is_admin()) with check (exists(select 1 from doctors d where d.id=doctor_id and d.auth_user_id=auth.uid()) or is_admin());
create policy "tenant qr" on qr_codes for all using (exists(select 1 from doctors d where d.id=doctor_id and d.auth_user_id=auth.uid()) or is_admin()) with check (exists(select 1 from doctors d where d.id=doctor_id and d.auth_user_id=auth.uid()) or is_admin());
create policy "public scan insert" on scans for insert with check (exists(select 1 from doctors d where d.id=doctor_id and d.is_active=true)); create policy "tenant scan read" on scans for select using (exists(select 1 from doctors d where d.id=doctor_id and d.auth_user_id=auth.uid()) or is_admin());
create policy "tenant reviews" on generated_reviews for select using (exists(select 1 from doctors d where d.id=doctor_id and d.auth_user_id=auth.uid()) or is_admin());
create policy "admins self read" on admins for select using (auth_user_id=auth.uid());
